sys_script.script:
(function executeRule(current, previous /*null when async*/ ) {
    //Check if current L2 assignment group is in Shift or having any active Shift
    var shift = new EQIX_ShiftSchedule_Utils();
    var checkL2InShift = shift.checkL2isInSchedule(current.assignment_group);
    var l1group = '';
    var analyst;
    var checkAvailableAnalyst;
    var groupType = current.assignment_group.type;

    //If current L2 assignment group is in Shift
    if (checkL2InShift == true) {
        //Check current assignee is available or not
        var checkL2AssigneeAvailability = shift.checkL2AssigneeAvailability(current.assigned_to);
        //If current assignee is available then return, else get another analyst which is available and with low workload in the same L2 group
        if (checkL2AssigneeAvailability == true) {
            return;
        } else {
            analyst = shift.getAssignedTo(current.assignment_group, current.u_service_type, current.u_hardware_type, current.u_application_name, current.assigned_to);
            if (analyst != '') {
                current.assigned_to = analyst;
            }
            //If there is no any analyst is available in the same L2 group for same region, then reassign to L1 group there is any available analyst in L1 group with low workload
            else {
                if (groupType.indexOf('L1') == -1) {
                    // AMER Region
                    if (current.u_operational_scope == 'AMER') {
                        l1group = gs.getProperty('EMS L1 OpsCenter AMER');
                        checkL1analystAvailability(l1group);
                    }
                    //APAC Region
                    else if (current.u_operational_scope == 'APAC') {
                        l1group = gs.getProperty('EMS L1 OpsCenter APAC');
                        checkL1analystAvailability(l1group);
                    }
                    //EMEA Region
                    else if (current.u_operational_scope == 'EMEA') {
                        l1group = gs.getProperty('EMS L1 OpsCenter EMEA');
                        checkL1analystAvailability(l1group);
                    }
                }
            }
        }

    }


    //If current L2 assignment group is not in Shift
    else {
        // AMER Region
        if (groupType.indexOf('L1') == -1) {
            if (current.u_operational_scope == 'AMER') {
                l1group = gs.getProperty('EMS L1 OpsCenter AMER');
                checkL1analystAvailability(l1group);
            }
            //APAC Region
            else if (current.u_operational_scope == 'APAC') {
                l1group = gs.getProperty('EMS L1 OpsCenter APAC');
                checkL1analystAvailability(l1group);
            }
            //EMEA Region
            else if (current.u_operational_scope == 'EMEA') {
                l1group = gs.getProperty('EMS L1 OpsCenter EMEA');
                checkL1analystAvailability(l1group);
            }
        }
    }

    function checkL1analystAvailability(l1RegionGroup) {
        var l1group = l1RegionGroup;
        //Check L1 group analyst availability
        checkAvailableAnalyst = shift.checkAssigneeAvailability(l1group);
        //If there is not available analyst in L1 then return, else reassign to L1 group available analyst with low workload
        if (checkAvailableAnalyst == false) {
            current.assignment_group = l1group;
            current.assigned_to = '';
            current.state = 10;
        } else {
            current.assignment_group = l1group;
            analyst = shift.getAssignedTo(current.assignment_group, current.u_service_type, current.u_hardware_type, current.u_application_name, current.assigned_to);

            if (analyst != '') {
                current.assigned_to = analyst;
            } else {
                current.assignment_group = l1group;
                current.assigned_to = '';
                current.state = 10;
            }
        }
    }

})(current, previous);
